// src/lib/dedupe.ts

// D5 (algorithmic hot spot): O(n^2) — a nested loop compares every pair of items to
// find duplicates. On a 10k-item list that is ~50M comparisons.
export function findDuplicates(items: { id: string }[]): string[] {
  const dupes: string[] = [];
  for (let i = 0; i < items.length; i++) {
    for (let j = i + 1; j < items.length; j++) {
      if (items[i].id === items[j].id) {
        dupes.push(items[i].id);
      }
    }
  }
  return dupes;
}

// D8 (concurrency): sequential await inside the loop — each fetch waits for the previous
// one to finish, so N ids take N round-trips of latency instead of one.
export async function enrich(
  ids: string[],
  fetchOne: (id: string) => Promise<unknown>,
): Promise<unknown[]> {
  const out: unknown[] = [];
  for (const id of ids) {
    out.push(await fetchOne(id));
  }
  return out;
}

// src/lib/dedupe.ts

// EFFICIENT: O(n) single pass with a Set — each id is checked/inserted in O(1), so the
// whole scan is linear, not quadratic.
export function findDuplicates(items: { id: string }[]): string[] {
  const seen = new Set<string>();
  const dupes: string[] = [];
  for (const item of items) {
    if (seen.has(item.id)) {
      dupes.push(item.id);
    } else {
      seen.add(item.id);
    }
  }
  return dupes;
}

// EFFICIENT: Promise.all fires every fetch concurrently, so N ids cost ~one round-trip of
// latency instead of N serial ones.
export async function enrich(
  ids: string[],
  fetchOne: (id: string) => Promise<unknown>,
): Promise<unknown[]> {
  return Promise.all(ids.map((id) => fetchOne(id)));
}
